import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.DLWhSH9p.js";const h=JSON.parse('{"title":"Feedback","description":"","frontmatter":{},"headers":[],"relativePath":"guide/feedback.md","filePath":"guide/feedback.md"}'),s={name:"guide/feedback.md"};function n(r,e,l,u,d,g){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="feedback" tabindex="-1">Feedback <a class="header-anchor" href="#feedback" aria-label="Permalink to &quot;Feedback&quot;">​</a></h1><p>The Feedback panel lets you submit suggestions, bug reports, and content ideas that get refined by AI. When the studio is configured for it, submissions become GitHub Issues; otherwise they&#39;re logged server-side with your user + channel context for an operator to triage.</p><h2 id="opening-the-panel" tabindex="-1">Opening the Panel <a class="header-anchor" href="#opening-the-panel" aria-label="Permalink to &quot;Opening the Panel&quot;">​</a></h2><p>Click <strong>Feedback</strong> in the top bar&#39;s right rail. The link is always visible.</p><h2 id="submitting-feedback" tabindex="-1">Submitting Feedback <a class="header-anchor" href="#submitting-feedback" aria-label="Permalink to &quot;Submitting Feedback&quot;">​</a></h2><ol><li><strong>Title</strong> -- a brief summary of your feedback</li><li><strong>Description</strong> -- detailed explanation of the suggestion, bug, or idea</li><li><strong>Channel</strong> (optional) -- associate the feedback with a specific channel for context</li></ol><h2 id="ai-grooming" tabindex="-1">AI Grooming <a class="header-anchor" href="#ai-grooming" aria-label="Permalink to &quot;AI Grooming&quot;">​</a></h2><p>Click <strong>Groom with AI</strong> to have the local Ollama model analyze and refine your feedback. The AI returns:</p><ul><li><strong>Refined Title</strong> -- a clearer, more actionable version</li><li><strong>Summary</strong> -- 1-2 sentence distillation</li><li><strong>Action Items</strong> -- concrete checklist of things to do</li><li><strong>Labels</strong> -- categorization tags (e.g., &quot;bug&quot;, &quot;feature&quot;, &quot;content-idea&quot;)</li><li><strong>Priority</strong> -- low, medium, or high based on impact</li><li><strong>Suggestions</strong> -- tips to improve or expand the feedback</li></ul><p>All fields are editable after grooming -- tweak anything before submitting.</p><h2 id="submitting" tabindex="-1">Submitting <a class="header-anchor" href="#submitting" aria-label="Permalink to &quot;Submitting&quot;">​</a></h2><p>Click <strong>Submit</strong> to send the feedback. Depending on how your studio is configured:</p><ul><li><strong>GitHub-connected studio</strong> — the button reads &quot;Submit to GitHub&quot; and an issue is filed in the configured repository.</li><li><strong>Logging-only studio</strong> — the button reads &quot;Submit feedback&quot; and the submission is logged for an operator to review.</li></ul><p>The issue (or log entry) includes:</p><ul><li>Refined title as the issue title</li><li>Markdown body with summary, action items checklist, original description, suggestions, and metadata</li><li>Labels from the groomed result plus a <code>feedback</code> label</li><li>Your username so the issue is attributed to you</li></ul><p>The submission runs as an async background job. You&#39;ll see real-time status updates and a link to the created issue once complete.</p><div class="info custom-block"><p class="custom-block-title">Requirements</p><ul><li>AI grooming uses your studio&#39;s local model, so it works whenever the local model service is reachable. Ask your administrator if the <strong>Groom with AI</strong> button is greyed out.</li><li>GitHub forwarding is optional — without it, submissions log server-side; with it, a real issue is created.</li></ul></div><h2 id="re-grooming" tabindex="-1">Re-grooming <a class="header-anchor" href="#re-grooming" aria-label="Permalink to &quot;Re-grooming&quot;">​</a></h2><p>Click <strong>Re-groom</strong> to run the AI analysis again with your edited fields. This is useful if you&#39;ve substantially changed the description after the first grooming pass.</p>',19)])])}const b=t(s,[["render",n]]);export{h as __pageData,b as default};
